// generar_242_signos_alerta_tips.js
// CHIQUI Entre Señales — Grupo de ChiquiTips "Signos de alerta" + novedad
// que invita a leerlos
//
// Qué hace:
// 1) components/ChiquiTeCuenta.tsx → nuevo grupo temático 8 "🚨 Signos
//    de alerta" con 5 tarjetas por especie: convulsión, golpe de calor,
//    intoxicación, accidente/caída, dificultad respiratoria. Cada una
//    explica cómo reconocerla, qué HACER y qué EVITAR — orientación
//    inicial, sin reemplazar al vet. El chip aparece en el selector de
//    categoría y el azar ahora rota entre 8 grupos (antes 7). También
//    se agrega la tarjeta de portada correspondiente (con chiqui_alerta).
// 2) components/Novedades.tsx → cada 4 días, en vez del mensaje
//    positivo, aparece una novedad con Chiqui lentes que dice
//    "Al final del dashboard te dejé ChiquiTips que te pueden ayudar
//    a entender mejor a {nombre}" — refuerza que existen sin cansar.
//
// No hay SQL.
//
// Uso:
//   node generar_242_signos_alerta_tips.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "components/ChiquiTeCuenta.tsx",
    base64: ""
  },
  {
    ruta: "components/Novedades.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 2 archivos escritos. git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
